practice_tasks.solution:
def classify_status(code):
    if 200 <= code <= 299:
        return 'success'
    elif 400 <= code <= 499:
        return 'client_error'
    elif 500 <= code <= 599:
        return 'server_error'
    else:
        return 'unknown'

